using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1 – Discriminator property renamed from "Discriminator" to "$type".
            // Existing documents use "Discriminator"; keep the old name.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change 2 – Id value no longer contains discriminator prefix.
            // EF8 stored a shadow "__id" = "Blog|<key>" as the JSON "id", and the
            // CLR Id went to a separate JSON property "Id".
            // EF9 maps the CLR Id directly to JSON "id", so reading an old document
            // would load "Blog|1" into Blog.Id instead of "1".
            // Fix: remap CLR Id back to JSON "Id" so it keeps reading the clean key,
            // and add a shadow __id that maps to JSON "id" with the old composite format.
            b.Property(e => e.Id).ToJsonProperty("Id");
            b.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3 – HasIndex now throws for the Cosmos provider
            // (previously silently ignored). Removed.
            // REMOVED: b.HasIndex(b => b.Name);
        });
    }
}

/// <summary>
/// Generates Cosmos "id" values in the legacy EF8 format: "{Discriminator}|{Key}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString();
        var key = entry.Property("Id").CurrentValue?.ToString();
        return $"{discriminator}|{key}";
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

